static Entry
entry_get(Rec rec, char *key)
{
	int i = hash(key) % rec->cap;
	char *s;

	while ((s = rec->items[i].key)) {
		if (!strcmp(s, key))
			break;
		if (++i == rec->cap) 
			i = 0;
	}
	return &rec->items[i]; 
}
