	rec->cap *= TSP_REC_FACTOR;
	if (!(rec->items = calloc(rec->cap, sizeof(struct Entry))))
		perror("; calloc"), exit(1);
	for (i = 0; i < ocap; i++) 
		if (oitems[i].key)
			rec_add(rec, oitems[i].key, oitems[i].val);
	free(oitems);
}
static void
