	rec_add(r, "this", ret);
	for (Val cur = assoc; cur->t == TSP_PAIR; cur = cdr(cur))
		if (car(cur)->t == TSP_PAIR && caar(cur)->t & (TSP_SYM|TSP_STR)) {
			if (!(v = tisp_eval(st, r, cdar(cur)->v.p.car)))
				return NULL;
