		tsp_finc(st);
		if (!(lst = read_pair(st, ')'))) return NULL;
		return mk_pair(v, lst);
	} else if (tsp_fget(st) == '{') { 
		tsp_finc(st);
		if (!(lst = read_pair(st, '}'))) return NULL;
		return mk_list(st, 3, mk_sym(st, "recmerge"), v,
		                      mk_pair(mk_sym(st, "Rec"), lst));
	} else if (tsp_fget(st) == ':') {
		tsp_finc(st);
